import { updateShoppingProfile } from "./shopping-profile.mjs";
import { ASOS_RETAILER, stageAsosCartItem } from "./asos-cart-staging-recipe.mjs";
import { ASKET_RETAILER, stageAsketCartItem } from "./asket-cart-staging-recipe.mjs";
import {
  recordRetailerManualStagingSuccess,
  recordRetailerStagingFailure,
} from "./retailer-circuit-breaker.mjs";

export const SHOPPING_CHAT_LOW_CONFIDENCE_MESSAGE =
  "I found shopping intent, but I am not confident enough to make a proposal yet.";
export const ASKET_CART_URL = "https://www.asket.com/cart";
export const ASOS_CART_URL = "https://www.asos.com/basket/";
export const SHOPPING_FEED_ITEM_TYPE = "shopping_feed_item";

const DEFAULT_MIN_PROPOSAL_CONFIDENCE = 0.7;
const DEFAULT_PROFILE_CONFIRMATION_MESSAGE = "Got it. I saved that to your shopping profile.";

const GARMENT_CLASS_ALIASES = Object.freeze({
  accessories: ["accessory", "accessories", "bag", "belt", "cap", "hat", "scarf"],
  bottoms: [
    "bottom",
    "bottoms",
    "chino",
    "chinos",
    "jean",
    "jeans",
    "pant",
    "pants",
    "shorts",
    "trouser",
    "trousers",
  ],
  dresses: ["dress", "dresses"],
  outerwear: ["coat", "jacket", "outerwear", "parka"],
  shoes: [
    "boot",
    "boots",
    "loafer",
    "loafers",
    "sandal",
    "sandals",
    "shoe",
    "shoes",
    "sneaker",
    "sneakers",
  ],
  tops: ["hoodie", "shirt", "shirts", "sweater", "t-shirt", "tee", "top", "tops"],
  underwear: ["boxer", "boxers", "brief", "briefs", "underwear"],
});

const SHOPPING_INTENT_TERMS = Object.freeze([
  "buy",
  "find",
  "get",
  "need",
  "order",
  "purchase",
  "shop",
  "shopping",
  "source",
  "want",
]);

export async function handleShoppingChatMessage({
  message,
  profile,
  pendingProfileField,
  confirmedProfileField,
  profilePath,
  updateProfile = updateShoppingProfile,
  searchTool,
  renderConfirmationCard = createProfileConfirmationCard,
  renderProposalCard,
  chat,
  minProposalConfidence = DEFAULT_MIN_PROPOSAL_CONFIDENCE,
} = {}) {
  const text = normalizeMessage(message);

  if (confirmedProfileField) {
    return confirmProfileField({
      chat,
      confirmedProfileField,
      profilePath,
      updateProfile,
    });
  }

  if (pendingProfileField) {
    const pendingFact = extractPendingProfileFact(text, pendingProfileField, profile);
    if (!pendingFact) {
      return askClarification(chat, createProfileQuestion(pendingProfileField));
    }

    const confirmationCard = await renderConfirmationCard(pendingFact);
    await publishConfirmationCard(chat, confirmationCard, pendingFact);
    return {
      action: "confirmation_card",
      confirmationCard,
      pendingProfileField: pendingFact,
    };
  }

  const shoppingIntent = detectShoppingIntent(text);

  if (!shoppingIntent.detected) {
    return {
      action: "none",
      reason: "no_shopping_intent",
      shoppingIntent,
    };
  }

  const missingBootstrapField = profile ? findMissingBootstrapField(profile) : undefined;
  if (missingBootstrapField) {
    return askClarification(chat, {
      ...createProfileQuestion(missingBootstrapField),
      shoppingIntent,
    });
  }

  const garmentClass = extractGarmentClass(text);
  if (!garmentClass) {
    return askClarification(chat, {
      field: "garmentClass",
      message: "What kind of garment should I search for?",
      shoppingIntent,
    });
  }

  const size = extractExplicitSize(text) ?? resolveProfileSize(profile, garmentClass);
  if (!size) {
    return askClarification(chat, {
      field: "size",
      message: `What size should I use for ${garmentClass}?`,
      shoppingIntent,
      context: { garmentClass },
    });
  }

  const priceCeiling =
    extractPriceCeiling(text, profile) ?? resolveProfileBudget(profile, garmentClass);
  if (!priceCeiling) {
    return askClarification(chat, {
      field: "priceCeiling",
      message: `What is the maximum price per item for ${garmentClass}?`,
      shoppingIntent,
      context: { garmentClass, size },
    });
  }

  if (!searchTool || typeof searchTool.search !== "function") {
    throw new TypeError("searchTool.search must be a function.");
  }

  const searchContext = {
    garmentClass,
    memories: Array.isArray(profile?.memories) ? profile.memories : [],
    originalMessage: text,
    priceCeiling,
    size,
  };
  const enabledRetailers = normalizeEnabledRetailers(profile?.enabledRetailers);
  const searchResult =
    enabledRetailers.length === 0
      ? await searchTool.search(searchContext)
      : await searchEnabledRetailersInParallel({
          context: searchContext,
          enabledRetailers,
          renderProposalCard,
          searchTool,
          chat,
        });
  const confidence = normalizeConfidence(searchResult?.confidence);

  if (confidence < minProposalConfidence) {
    await publishPlainText(chat, SHOPPING_CHAT_LOW_CONFIDENCE_MESSAGE, {
      confidence,
      context: searchContext,
      reason: "low_confidence",
      searchResult,
    });
    return {
      action: "plain_text",
      confidence,
      context: searchContext,
      message: SHOPPING_CHAT_LOW_CONFIDENCE_MESSAGE,
      reason: "low_confidence",
      searchResult,
      shoppingIntent,
    };
  }

  if (!renderProposalCard || typeof renderProposalCard !== "function") {
    throw new TypeError("renderProposalCard must be a function.");
  }

  const proposalCard = await renderProposalCard(searchResult, searchContext);
  return {
    action: "proposal_card",
    confidence,
    context: searchContext,
    proposalCard,
    searchResult,
    shoppingIntent,
  };
}

export function findMissingBootstrapField(profile) {
  if (!profile?.country) {
    return {
      field: "country",
      label: "country",
      profileKey: "country",
    };
  }

  if (!profile?.sizes?.tops?.value) {
    return {
      field: "topSize",
      garmentClass: "tops",
      label: "top size",
      profileKey: "sizes.tops",
    };
  }

  if (!profile?.sizes?.shoes?.value) {
    return {
      field: "shoeSizeEu",
      garmentClass: "shoes",
      label: "EU shoe size",
      profileKey: "sizes.shoes",
    };
  }

  if (!resolveProfileBudget(profile, "default")) {
    return {
      field: "roughBudget",
      label: "rough budget",
      profileKey: "budgetAnchors.default",
    };
  }

  return undefined;
}

export function createProfileConfirmationCard(profileFact) {
  const normalized = normalizeProfileFact(profileFact);
  return {
    type: "profile_confirmation_card",
    title: `Confirm ${normalized.label}`,
    body: formatProfileFactValue(normalized),
    confirmLabel: "Confirm",
    value: normalized.value,
    profileField: {
      field: normalized.field,
      garmentClass: normalized.garmentClass,
      label: normalized.label,
      profileKey: normalized.profileKey,
      value: normalized.value,
    },

import test from "node:test";
import assert from "node:assert/strict";

import {
  ASKET_CART_URL,
  ASOS_CART_URL,
  SHOPPING_CHAT_LOW_CONFIDENCE_MESSAGE,
  createStagingFailureExplanation,
  createDiscoveryOnlyRetailerFeedItem,
  createProfileConfirmationCard,
  detectShoppingIntent,
  findMissingBootstrapField,
  handleShoppingChatMessage,
  renderAsketStagingResultCard,
  renderAsosStagingResultCard,
  renderRetailerStagingFailureCard,
  stageSelectedAsketCandidates,
  stageSelectedAsosCandidates,
} from "../src/shopping-chat-flow.mjs";
import {
  createRetailerCircuitBreakerState,
  getRetailerCircuitBreakerStatus,
  recordRetailerStagingFailure,
} from "../src/retailer-circuit-breaker.mjs";

test("detects shopping intent in a garment request", () => {
  assert.deepEqual(detectShoppingIntent("Find me black jeans under 100 euros"), {
    detected: true,
    garmentClass: "bottoms",
  });
});

test("asks for garment class before searching when the request is underspecified", async () => {
  const events = [];
  const result = await handleShoppingChatMessage({
    chat: {
      async say(message, payload) {
        events.push([message, payload.field]);
      },
    },
    message: "Please find something for work",
    searchTool: failSearchTool(),
  });

  assert.equal(result.action, "clarify");
  assert.equal(result.field, "garmentClass");
  assert.deepEqual(events, [["What kind of garment should I search for?", "garmentClass"]]);
});

test("asks for size before searching when neither text nor profile provides one", async () => {
  const result = await handleShoppingChatMessage({
    message: "Find a shirt under 80 euros",
    searchTool: failSearchTool(),
  });

  assert.equal(result.action, "clarify");
  assert.equal(result.field, "size");
  assert.equal(result.context.garmentClass, "tops");
});

test("asks for price ceiling when no explicit or profile budget is known", async () => {
  const result = await handleShoppingChatMessage({
    message: "Find shoes size 42",
    searchTool: failSearchTool(),
  });

  assert.equal(result.action, "clarify");
  assert.equal(result.field, "priceCeiling");
  assert.deepEqual(result.context.size, { value: "42" });
});

test("uses profile size and budget before dispatching search and rendering a proposal card", async () => {
  const searches = [];
  const cards = [];

  const result = await handleShoppingChatMessage({
    message: "Find a crisp shirt for the office",
    profile: {
      country: "LV",
      currency: "EUR",
      sizes: {
        shoes: { value: "42", system: "EU" },
        tops: { value: "M", system: "International" },
      },
      budgetAnchors: {
        default: { amount: 100, currency: "EUR", cadence: "per_item" },
        tops: { amount: 90, currency: "EUR", cadence: "per_item" },
      },
    },
    searchTool: {
      async search(context) {
        searches.push(context);
        return {
          confidence: 0.86,
          items: [{ id: "asket-shirt-1", title: "Oxford Shirt" }],
        };
      },
    },
    async renderProposalCard(searchResult, context) {
      cards.push([searchResult.items[0].id, context.garmentClass]);
      return { type: "proposal_card", itemId: searchResult.items[0].id };
    },
  });

  assert.equal(result.action, "proposal_card");
  assert.deepEqual(searches, [
    {
      garmentClass: "tops",
      memories: [],
      originalMessage: "Find a crisp shirt for the office",
      priceCeiling: { amount: 90, currency: "EUR" },
      size: { system: "International", value: "M" },
    },
  ]);
  assert.deepEqual(cards, [["asket-shirt-1", "tops"]]);
  assert.deepEqual(result.proposalCard, { type: "proposal_card", itemId: "asket-shirt-1" });
});

test("searches enabled retailers in parallel and assembles sorted non-empty proposal cards", async () => {
  const started = [];
  const incrementalCards = [];
  const gates = new Map([
    ["Slow Retailer", createDeferred()],
    ["Fast Retailer", createDeferred()],
    ["Empty Retailer", createDeferred()],
  ]);

  const pending = handleShoppingChatMessage({
    chat: {
      async showProposalCard(card, payload) {
        incrementalCards.push([card.retailer, payload.retailerResult.candidates.length]);
      },
    },
    message: "Find black shirt",
    profile: {
      country: "LV",
      currency: "EUR",
      enabledRetailers: ["Slow Retailer", "Fast Retailer", "Empty Retailer"],
      sizes: {
        shoes: { value: "42", system: "EU" },
        tops: { value: "M", system: "International" },
      },
      budgetAnchors: {
        default: { amount: 100, currency: "EUR", cadence: "per_item" },
      },
    },
    searchTool: {
      async search(context) {
        started.push(context.retailer);
        return gates.get(context.retailer).promise;
      },
    },
    async renderProposalCard(searchResult) {
      return {
        retailer: searchResult.retailer,
        type: searchResult.type ?? "retailer_proposal_card",
      };
    },
  });

  await Promise.resolve();
  assert.deepEqual(started, ["Slow Retailer", "Fast Retailer", "Empty Retailer"]);

  gates.get("Fast Retailer").resolve({
    retailer: "Fast Retailer",
    confidence: 0.81,
    overallMatchScore: 72,
    candidates: [createSearchCandidate("fast-1")],
  });
  await flushAsyncWork();
