export function findMissingBootstrapField(profile) {
  if (!profile?.country) {
    return {
      field: "country",
      label: "country",
      profileKey: "country",
    };
  }

  if (!profile?.sizes?.tops?.value) {
    return {
      field: "topSize",
      garmentClass: "tops",
      label: "top size",
      profileKey: "sizes.tops",
    };
  }

  if (!profile?.sizes?.shoes?.value) {
    return {
      field: "shoeSizeEu",
      garmentClass: "shoes",
      label: "EU shoe size",
      profileKey: "sizes.shoes",
