import { detectShoppingIntent } from "./shopping-chat-flow.mjs";

export const SHOP_INBOX_TRIAGE_ACTION_ID = "shop";
export const SHOP_INBOX_TRIAGE_SHORTCUT = "4";
export const SHOP_INBOX_TRIAGE_POSITION = 5;

export function createInboxTriageActions({
  captureText,
  existingActions = [],
  detectIntent = detectShoppingIntent,
} = {}) {
  const actions = normalizeExistingActions(existingActions);
  const text = normalizeCaptureText(captureText);

  if (!text) {
    return actions;
  }
  if (actions.some((action) => action.id === SHOP_INBOX_TRIAGE_ACTION_ID)) {
    return actions;
  }
  if (typeof detectIntent !== "function") {
    throw new TypeError("detectIntent must be a function.");
  }

  const shoppingIntent = detectIntent(text);
  if (!shoppingIntent?.detected) {
    return actions;
  }

  return [
    ...actions,
    createShopInboxTriageAction({
      captureText: text,
      shoppingIntent,
    }),
  ];
}

export function createShopInboxTriageAction({ captureText, shoppingIntent } = {}) {
  const text = normalizeNonEmptyString(captureText, "captureText");

  return {
    id: SHOP_INBOX_TRIAGE_ACTION_ID,
    intent: "shopping",
    label: "Shop",
    position: SHOP_INBOX_TRIAGE_POSITION,
    shortcut: SHOP_INBOX_TRIAGE_SHORTCUT,
    type: "inbox_triage_action",
    payload: {
      captureText: text,
      shoppingIntent: shoppingIntent ?? detectShoppingIntent(text),
    },
  };
}

export function resolveInboxTriageShortcut({ key, actions } = {}) {
  const normalizedKey = String(key ?? "").trim();
  if (!normalizedKey) {
    return undefined;
  }

  return normalizeExistingActions(actions).find((action) => action.shortcut === normalizedKey);
}

export async function acceptInboxShopTriage({
  action,
  captureText,
  openNewChat,
} = {}) {
  const actionPayload = normalizeShopInboxTriageAction(action);
  const text = normalizeNonEmptyString(
    captureText ?? actionPayload.payload.captureText,
    "captureText",
  );

  if (typeof openNewChat !== "function") {
    throw new TypeError("openNewChat must be a function.");
  }

  const chat = await openNewChat({
    initialMessage: text,
    source: "inbox",
    triageAction: SHOP_INBOX_TRIAGE_ACTION_ID,
  });

  return {
    action: "shop_triage_accepted",
    chat,
    initialMessage: text,
    triageAction: actionPayload,
  };
}

function normalizeShopInboxTriageAction(action) {
  if (!action || typeof action !== "object" || Array.isArray(action)) {
    throw new TypeError("Shop triage action is required.");
  }
  if (action.id !== SHOP_INBOX_TRIAGE_ACTION_ID) {
    throw new TypeError("Expected a Shop triage action.");
  }
  if (!action.payload || typeof action.payload !== "object" || Array.isArray(action.payload)) {
    throw new TypeError("Shop triage action payload is required.");
  }
  return action;
}

function normalizeExistingActions(actions) {
  if (actions === undefined) {
    return [];
  }
  if (!Array.isArray(actions)) {
    throw new TypeError("existingActions/actions must be an array.");
  }
  return actions.map((action) => {
    if (!action || typeof action !== "object" || Array.isArray(action)) {
      throw new TypeError("Inbox triage actions must be objects.");
    }
    return action;
  });
}

function normalizeCaptureText(value) {
  if (value === undefined || value === null) {
    return "";
  }
  return String(value).trim();
}

function normalizeNonEmptyString(value, name) {
  const text = normalizeCaptureText(value);
  if (!text) {
    throw new TypeError(`${name} must be a non-empty string.`);
  }
  return text;
}

import test from "node:test";
import assert from "node:assert/strict";

import {
  SHOP_INBOX_TRIAGE_ACTION_ID,
  SHOP_INBOX_TRIAGE_POSITION,
  SHOP_INBOX_TRIAGE_SHORTCUT,
  acceptInboxShopTriage,
  createInboxTriageActions,
  resolveInboxTriageShortcut,
} from "../src/inbox-triage-actions.mjs";

test("adds Shop as the fifth Inbox triage action when shopping intent is detected", () => {
  const actions = createInboxTriageActions({
    captureText: "Need black jeans under 100 euros",
    existingActions: createBaseInboxActions(),
  });

  assert.equal(actions.length, 5);
  assert.deepEqual(actions.slice(0, 4), createBaseInboxActions());

  const shopAction = actions[4];
  assert.equal(shopAction.id, SHOP_INBOX_TRIAGE_ACTION_ID);
  assert.equal(shopAction.label, "Shop");
  assert.equal(shopAction.position, SHOP_INBOX_TRIAGE_POSITION);
  assert.equal(shopAction.shortcut, SHOP_INBOX_TRIAGE_SHORTCUT);
  assert.deepEqual(shopAction.payload, {
    captureText: "Need black jeans under 100 euros",
    shoppingIntent: {
      detected: true,
      garmentClass: "bottoms",
    },
  });
});

test("does not add Shop when shopping intent is not detected", () => {
  const baseActions = createBaseInboxActions();
  const actions = createInboxTriageActions({
    captureText: "Remember to call the plumber tomorrow",
    existingActions: baseActions,
  });

  assert.deepEqual(actions, baseActions);
});

test("keyboard shortcut 4 resolves the Shop triage action", () => {
  const actions = createInboxTriageActions({
    captureText: "Find a linen shirt size M",
    existingActions: createBaseInboxActions(),
  });

  const action = resolveInboxTriageShortcut({ actions, key: "4" });

  assert.equal(action.id, SHOP_INBOX_TRIAGE_ACTION_ID);
  assert.equal(action.label, "Shop");
});

test("accepting Shop opens a new chat pre-seeded with the capture text", async () => {
  const [shopAction] = createInboxTriageActions({
    captureText: "Buy office sneakers EU 42 under 120 euros",
    existingActions: [],
  });
  const openedChats = [];

  const result = await acceptInboxShopTriage({
    action: shopAction,
    async openNewChat(payload) {
      openedChats.push(payload);
      return { id: "chat-1", ...payload };
    },
  });

  assert.deepEqual(openedChats, [
    {
      initialMessage: "Buy office sneakers EU 42 under 120 euros",
      source: "inbox",
      triageAction: SHOP_INBOX_TRIAGE_ACTION_ID,
    },
  ]);
  assert.equal(result.action, "shop_triage_accepted");
  assert.equal(result.initialMessage, "Buy office sneakers EU 42 under 120 euros");
  assert.deepEqual(result.chat, {
    id: "chat-1",
    initialMessage: "Buy office sneakers EU 42 under 120 euros",
    source: "inbox",
    triageAction: SHOP_INBOX_TRIAGE_ACTION_ID,
  });
});

